#!/usr/bin/env node
'use strict';

const { execSync } = require('child_process');

const REPO_ROOT = process.env.FACTORY_REPO_ROOT || process.cwd();

const PATTERNS = [
  'Co-Authored-By:.*Claude',
  'Co-Authored-By:.*Anthropic',
  'Co-Authored-By:.*OpenAI',
  'Co-Authored-By:.*GPT',
  'Co-Authored-By:.*Copilot',
  'Generated with.*Claude',
  'Generated with.*AI',
  'Generated by.*Claude',
  'Generated by.*AI',
  'AI-generated',
  'LLM-generated',
  'noreply@anthropic\\.com',
  'noreply@openai\\.com',
];

function run() {
  const violations = [];

  for (const pattern of PATTERNS) {
    try {
      // Check staged files
      const staged = execSync(
        `git diff --cached --unified=0 | grep -iE "${pattern}" || true`,
        { cwd: REPO_ROOT, encoding: 'utf-8', timeout: 30000 }
      ).trim();

      if (staged) {
        violations.push({ pattern, location: 'staged', match: staged.slice(0, 200) });
      }

      // Check last 3 commit messages
      const commits = execSync(
        `git log -3 --format="%B" | grep -iE "${pattern}" || true`,
        { cwd: REPO_ROOT, encoding: 'utf-8', timeout: 30000 }
      ).trim();

      if (commits) {
        violations.push({ pattern, location: 'recent-commits', match: commits.slice(0, 200) });
      }
    } catch {
      // grep returns non-zero on no match, which is fine
    }
  }

  console.log(JSON.stringify({
    check: 'no-attribution',
    status: violations.length === 0 ? 'pass' : 'fail',
    violations,
    details: violations.length === 0
      ? 'No AI attribution markers found'
      : `Found ${violations.length} attribution marker(s)`,
  }));
}

run();
